import{_ as n,o as a,c as i,ag as e}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"Hướng dẫn Quản lý Thay đổi Tài liệu (Documentation Change Management)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/01-nen-tang-he-thong/00-huong-dan-cap-nhat-doc.md","filePath":"99-tham-khao/archive/01-nen-tang-he-thong/00-huong-dan-cap-nhat-doc.md"}'),o={name:"99-tham-khao/archive/01-nen-tang-he-thong/00-huong-dan-cap-nhat-doc.md"};function h(c,t,l,r,u,g){return a(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="huong-dan-quan-ly-thay-đoi-tai-lieu-documentation-change-management" tabindex="-1">Hướng dẫn Quản lý Thay đổi Tài liệu (Documentation Change Management) <a class="header-anchor" href="#huong-dan-quan-ly-thay-đoi-tai-lieu-documentation-change-management" aria-label="Permalink to &quot;Hướng dẫn Quản lý Thay đổi Tài liệu (Documentation Change Management)&quot;">​</a></h1><p>Chào mừng bạn đến với quy trình duy trì &quot;Single Source of Truth&quot; cho Vivu Travel. Khi dự án phát triển qua từng Sprint, việc cập nhật tài liệu là bắt buộc để tránh sự sai lệch giữa Spec và Code.</p><h2 id="_1-nguyen-tac-single-source-of-truth" tabindex="-1">1. Nguyên tắc &quot;Single Source of Truth&quot; <a class="header-anchor" href="#_1-nguyen-tac-single-source-of-truth" aria-label="Permalink to &quot;1. Nguyên tắc &quot;Single Source of Truth&quot;&quot;">​</a></h2><ul><li><strong>Product Backlog (Mục 02)</strong>: Phải luôn phản ánh trạng thái <strong>mới nhất</strong> của tính năng. Nếu Sprint 5 thay đổi logic của Sprint 2, hãy sửa trực tiếp vào file nghiệp vụ tại mục 02.</li><li><strong>Sprint Backlog (Mục 03)</strong>: Chỉ ghi nhận các <strong>thay đổi cụ thể (Delta)</strong> phát sinh trong Sprint đó và link tới Product Backlog đã được cập nhật.</li></ul><h2 id="_2-quy-trinh-cap-nhat-tai-lieu-workflow" tabindex="-1">2. Quy trình Cập nhật Tài liệu (Workflow) <a class="header-anchor" href="#_2-quy-trinh-cap-nhat-tai-lieu-workflow" aria-label="Permalink to &quot;2. Quy trình Cập nhật Tài liệu (Workflow)&quot;">​</a></h2><h3 id="buoc-1-cap-nhat-lich-su-thay-đoi-change-log" tabindex="-1">Bước 1: Cập nhật Lịch sử Thay đổi (Change Log) <a class="header-anchor" href="#buoc-1-cap-nhat-lich-su-thay-đoi-change-log" aria-label="Permalink to &quot;Bước 1: Cập nhật Lịch sử Thay đổi (Change Log)&quot;">​</a></h3><p>Mỗi file trong Product Backlog cần có một bảng lịch sử ở đầu trang:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Phiên bản</th><th style="text-align:left;">Ngày</th><th style="text-align:left;">Sprint</th><th style="text-align:left;">Nội dung thay đổi</th><th style="text-align:left;">Người thực hiện</th></tr></thead><tbody><tr><td style="text-align:left;">v1.0</td><td style="text-align:left;">26/03</td><td style="text-align:left;"><a href="./../../02-quan-ly-sprint/sprint-2-quan-tri-diem-den/01-yeu-cau-nghiep-vu">Sprint 2</a></td><td style="text-align:left;">Khởi tạo đặc tả ban đầu</td><td style="text-align:left;">PO</td></tr></tbody></table><blockquote><p><strong>Quy tắc bắt buộc:</strong> Cột &quot;Sprint&quot; trong bảng phải là một <strong>Hyperlink</strong> dẫn trực tiếp tới tài liệu triển khai (Phạm vi &amp; AC) của Sprint đó để phục vụ việc truy vết dữ liệu (Traceability).</p></blockquote><h3 id="buoc-2-chinh-sua-noi-dung-chi-tiet" tabindex="-1">Bước 2: Chỉnh sửa nội dung chi tiết <a class="header-anchor" href="#buoc-2-chinh-sua-noi-dung-chi-tiet" aria-label="Permalink to &quot;Bước 2: Chỉnh sửa nội dung chi tiết&quot;">​</a></h3><ul><li>Thay đổi trực tiếp các đề mục, API Spec hoặc UI Mockup trong file để phản ánh thiết kế mới.</li><li>Đánh dấu các phần mới bằng label <code>[NEW]</code> hoặc <code>[UPDATED]</code> nếu cần gây chú ý cho Developer.</li></ul><h3 id="buoc-3-thong-bao-trong-sprint-backlog" tabindex="-1">Bước 3: Thông báo trong Sprint Backlog <a class="header-anchor" href="#buoc-3-thong-bao-trong-sprint-backlog" aria-label="Permalink to &quot;Bước 3: Thông báo trong Sprint Backlog&quot;">​</a></h3><p>Trong file <code>Phạm vi &amp; AC</code> của Sprint hiện tại, hãy thêm mục:</p><blockquote><p><strong>### 🛠 Thay đổi thiết kế so với phiên bản cũ</strong></p><ul><li>Thay đổi logic tính giá tour (Link tới Product Backlog v1.1).</li><li>Lý do: Tối ưu UX theo phản hồi của User Testing.</li></ul></blockquote><h2 id="_3-quan-ly-api-spec" tabindex="-1">3. Quản lý API Spec <a class="header-anchor" href="#_3-quan-ly-api-spec" aria-label="Permalink to &quot;3. Quản lý API Spec&quot;">​</a></h2><ul><li>Không xóa các Endpoint cũ nếu chúng đang được Mobile App cũ sử dụng.</li><li>Sử dụng versioning (e.g. <code>/api/v1/...</code> -&gt; <code>/api/v2/...</code>) trong tài liệu API Design nếu có thay đổi mang tính &quot;breaking change&quot;.</li></ul><hr><p><em>Tài liệu hướng dẫn duy trì hệ thống tri thức dự án.</em></p>',18)])])}const s=n(o,[["render",h]]);export{p as __pageData,s as default};
